// (2) sync_reset: Asynchronous reset of the counter. Active low.
// (3) clock: Clock signal.
// (4) output: 5-bit output of the counter.
module top_module(
	input clk,
	input enable,
	input reset,
	output reg [4:0] q);always @(posedge clk) begin
	if (reset)
		q <= 5'b00000;
	else if (enable)
		q <= q + 3;
end
endmodule

